import{_ as t,o,c as n,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G14: 戰略規劃與新業務展望","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G11_戰略規劃與新業務展望_產品趨勢研究員.md","filePath":"32Ｑ題本＿重要/經營組/G11_戰略規劃與新業務展望_產品趨勢研究員.md"}'),s={name:"32Ｑ題本＿重要/經營組/G11_戰略規劃與新業務展望_產品趨勢研究員.md"};function i(l,r,a,g,d,c){return o(),n("div",null,[...r[0]||(r[0]=[e('<h1 id="g14-戰略規劃與新業務展望" tabindex="-1">G14: 戰略規劃與新業務展望 <a class="header-anchor" href="#g14-戰略規劃與新業務展望" aria-label="Permalink to &quot;G14: 戰略規劃與新業務展望&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G11</li><li><strong>題目：</strong> 管理層給出的未來 3-5 年發展規劃與戰略目標為何？是否有具體的擴產或併購計畫？公司在最近三年中是否有增加新的業務展望或第二成長曲線？其技術儲備與市場佈局進度為何？</li><li><strong>推薦專家：</strong> 產品趨勢研究員 (<code>product-trend-researcher</code>)</li><li><strong>推薦理由：</strong> 專注於行業趨勢分析與技術前瞻。擅長辨識「第二成長曲線」的真實爆發力，能從全球產業演進的角度，判定公司新增業務是順應未來 3-5 年的趨勢風口，還是進入過度飽和的夕陽市場，識別「無效轉型」風險。同時能驗證戰略目標的資本支出支撐度。</li><li><strong>意圖：</strong> 執行「戰略規劃實質性與新業務成長動能審計」。結合戰略方向（願景）與新業務執行（落地），判定投資案的「未來預期溢價」，識別「畫大餅型願景」與「實質擴張型戰略」之差異點。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【趨勢對位核心：IDC / Gartner / 專業智庫報告】</strong>：獲取標的新業務所屬產業的「未來年複合成長率 (CAGR)」與市場規模 (TAM)。</li><li><strong>【願景與行動事實來源：Annual Report (年報)】</strong>：必須查閱 <code>致股東報告書 -&gt; 未來展望</code> 與 <code>業務概況 -&gt; 未來計畫</code>。提取管理層對戰略方向與新產品線的具體描述。</li><li><strong>【行動驗證：FinMind】</strong>：調用 <code>TaiwanStockCashFlowsStatement</code> 提取「投資活動現金流 -&gt; 購置固定資產 (CapEx)」。比對戰略願景與實際資金投入。</li><li><strong>【穿透校準：MOPS】</strong>：檢索「重大收購案」、「處分重大資產」或「董事會決議擴產」公告。</li><li><strong>【外部驗證：法人說明會 (Earnings Calls)】</strong>：查閱經營層對未來展望的具體口徑與分析師問答。</li></ol></li><li><strong>邏輯：</strong> 執行「行與言一致性測試」——真正的戰略規劃必須體現在「資本支出 (CapEx)」的增長上；若僅有願景而無資金流出，應判定為「宣傳性規劃」。同時執行「趨勢對位審計」——分析新業務是否具備較高的成長增速。</li><li><strong>來源：</strong> <code>公司致股東報告書</code>, <code>FinMind (資產支出數據)</code>, <code>重大訊息公告 (MOPS)</code>, <code>法說會展望簡報</code>, <code>產業趨勢報告 (Trend Reports)</code>, <code>專業機構市調數據</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【CapEx 真實性檢核】</strong>：智慧體<strong>必須</strong>檢索最近 4 季的「購置固定資產」金額。若管理層宣稱要大舉擴產但在財報上看不到對應支出，必須標註為「戰略執行度存疑」。</li><li><strong>【戰略連貫性審計】</strong>：搜尋該公司兩年前的法說會紀錄，比對當時承諾的「戰略目標」與今日的「達成進度」。若目標頻繁更換且無一達成，應下修其管理信用。</li><li><strong>【賽道趨勢對位】</strong>：智慧體<strong>必須</strong>檢索該新業務所處產業的未來前景。針對新賽道，<strong>強制列出其未來 5 年之市場規模 (TAM) 預測與年複合成長率 (CAGR)</strong>。若新業務進入的是紅海競爭或夕陽產業，必須在評級中給予警示。</li><li><strong>【早期信號捕獲與 Design-win】</strong>：智慧體<strong>必須</strong>檢索標的公司在新領域是否已取得「Design-win (設計贏取)」或「官方認證/樣品測試通過」之實質信號。若僅停留在「規劃階段」而無具體料號或驗證公告，必須下調評級。</li><li><strong>【描述指標】</strong>：絕對禁用「前景光明」、「計畫宏大」、「轉型成功」。必須量化為具體的「未來產能擴張 %」、「預計投資回報率 (ROA/ROE)」、「資產支出率 (CapEx/Sales)」、「新業務預計貢獻佔比」與「目標市場規模 (USD)」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g14-專家答詢】產品趨勢研究員-product-trend-researcher" tabindex="-1">【G14 專家答詢】產品趨勢研究員 (product-trend-researcher) <a class="header-anchor" href="#【g14-專家答詢】產品趨勢研究員-product-trend-researcher" aria-label="Permalink to &quot;【G14 專家答詢】產品趨勢研究員 (product-trend-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：直接判定其戰略規劃是「路徑清晰、具備財力支持且符合趨勢」、「過於激進、財務壓力大」、還是「目標模糊、具備畫大餅嫌疑」。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：戰略路徑清晰且已有明確的資本支出支撐，新業務位於高速成長賽道，且公司具備顯著的切入優勢，已有指標性訂單或 Design-win 實績。</li><li><strong>A (良)</strong>：具備明確成長方向與執行計畫，戰略方向正確，處於市場回報初期，技術研發進度符合預期。</li><li><strong>B (持平)</strong>：目標過於宏大但缺乏具體數據支撐，或與目前財務狀況存在明顯脫節，執行風險極高；或新業務與現有趨勢背離，轉型進度滯後。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind 投資現流數據、年報展望段落、重大訊息公告字號、市場研究報告數據。</li><li><strong>【專家建議】注意事項</strong>：提示投資人關注「擴產後的產能利用率」是否可能因市場飽和而導致資產減損風險，以及「該技術領域是否可能被新科技迅速取代」的顛覆性風險。</li></ul>',8)])])}const u=t(s,[["render",i]]);export{h as __pageData,u as default};
